"use strict";(self.webpackChunksite=self.webpackChunksite||[]).push([[656],{5463:n=>{n.exports=JSON.parse('{"lang":"vi","resources":{"landing":{"meta":{"title":"Linguist \u2013 Ti\u1ec7n \xedch m\u1edf r\u1ed9ng d\u1ecbch thu\u1eadt \u01b0u ti\xean quy\u1ec1n ri\xeang t\u01b0 cho Chrome v\xe0 Firefox","description":"Ti\u1ec7n \xedch m\u1edf r\u1ed9ng tr\xecnh duy\u1ec7t gi\xfap d\u1ecbch trang web, v\u0103n b\u1ea3n \u0111\u01b0\u1ee3c ch\u1ecdn v\xe0 ph\u1ee5 \u0111\u1ec1. Ho\u1ea1t \u0111\u1ed9ng t\u1ee9c th\xec v\xe0 h\u1ed7 tr\u1ee3 d\u1ecbch ngo\u1ea1i tuy\u1ebfn."},"navigation":{"features":{"content":"T\xednh n\u0103ng"},"blog":{"content":"Blog"},"docs":{"content":"T\xe0i li\u1ec7u"},"github":{"content":"GitHub"}},"install":{"chrome":"C\xe0i \u0111\u1eb7t cho Chrome","firefox":"C\xe0i \u0111\u1eb7t cho Firefox"},"sections":{"hero":{"title":"D\u1ecbch m\u1ecdi th\u1ee9 ngay tr\xean tr\xecnh duy\u1ec7t c\u1ee7a b\u1ea1n","description":"Linguist l\xe0 ti\u1ec7n \xedch m\u1edf r\u1ed9ng tr\xecnh duy\u1ec7t gi\xfap d\u1ecbch v\u0103n b\u1ea3n t\u1ee9c th\xec.\\n\\nD\u1ecbch to\xe0n b\u1ed9 trang web, v\u0103n b\u1ea3n \u0111\u01b0\u1ee3c ch\u1ecdn, ph\u1ee5 \u0111\u1ec1 Netflix v\xe0 tin nh\u1eafn ri\xeang t\u01b0. Nghe v\u0103n b\u1ea3n \u0111\xe3 d\u1ecbch v\xe0 l\u01b0u c\xe1c b\u1ea3n d\u1ecbch quan tr\u1ecdng v\xe0o t\u1eeb \u0111i\u1ec3n c\xe1 nh\xe2n \u0111\u1ec3 h\u1ecdc t\u1eeb m\u1edbi, ngay c\u1ea3 khi ngo\u1ea1i tuy\u1ebfn.\\n\\nLinguist l\xe0 m\u1ed9t gi\u1ea3i ph\xe1p thay th\u1ebf hi\u1ec7n \u0111\u1ea1i, \u01b0u ti\xean quy\u1ec1n ri\xeang t\u01b0 cho c\xe1c ti\u1ec7n \xedch m\u1edf r\u1ed9ng c\u1ee7a Google D\u1ecbch. H\xe3y d\xf9ng th\u1eed mi\u1ec5n ph\xed."},"opensource":{"title":"M\xe3 ngu\u1ed3n m\u1edf","content":"Linguist l\xe0 ti\u1ec7n \xedch m\u1edf r\u1ed9ng d\u1ecbch thu\u1eadt mi\u1ec5n ph\xed v\xe0 <0>m\xe3 ngu\u1ed3n m\u1edf</0>. Ti\u1ec7n \xedch n\xe0y kh\xf4ng thu th\u1eadp hay b\xe1n d\u1eef li\u1ec7u ng\u01b0\u1eddi d\xf9ng.\\n\\nB\u1ea1n c\xf3 th\u1ec3 <1>quy\xean g\xf3p</1> \u0111\u1ec3 \u1ee7ng h\u1ed9 Linguist v\xe0 gi\xfap ch\xfang t\xf4i duy tr\xec s\u1ef1 \u0111\u1ed9c l\u1eadp c\u0169ng nh\u01b0 ch\u1ea5t l\u01b0\u1ee3ng cao.\\n\\nH\xe3y chia s\u1ebb Linguist tr\xean m\u1ea1ng x\xe3 h\u1ed9i \u0111\u1ec3 gi\xfap nh\u1eefng ng\u01b0\u1eddi kh\xe1c bi\u1ebft \u0111\u1ebfn ti\u1ec7n \xedch n\xe0y."},"support":{"title":"H\u1ed7 tr\u1ee3","content":"N\u1ebfu b\u1ea1n c\xf3 c\xe2u h\u1ecfi, h\xe3y li\xean h\u1ec7 v\u1edbi ch\xfang t\xf4i <0/>.\\nN\u1ebfu b\u1ea1n ph\xe1t hi\u1ec7n l\u1ed7i v\xe0 c\xf3 t\xe0i kho\u1ea3n GitHub, vui l\xf2ng <1>t\u1ea1o b\xe1o c\xe1o l\u1ed7i</1>."},"createdBy":{"content":"\u0110\u01b0\u1ee3c t\u1ea1o b\u1edfi <0/>."}},"features":{"title":"T\xednh n\u0103ng","items":{"offlineTranslation":{"title":"D\u1ecbch ngo\u1ea1i tuy\u1ebfn v\xe0 quy\u1ec1n ri\xeang t\u01b0","content":"D\u1ecbch v\u0103n b\u1ea3n tr\u1ef1c ti\u1ebfp tr\xean thi\u1ebft b\u1ecb c\u1ee7a b\u1ea1n b\u1eb1ng tr\xecnh d\u1ecbch ngo\u1ea1i tuy\u1ebfn \u0111\u01b0\u1ee3c t\xedch h\u1ee3p s\u1eb5n. V\u0103n b\u1ea3n c\u1ee7a b\u1ea1n lu\xf4n \u0111\u01b0\u1ee3c gi\u1eef ri\xeang t\u01b0 v\xe0 kh\xf4ng b\u1ecb g\u1eedi qua internet.\\n\\nH\xe3y b\u1eadt t\xednh n\u0103ng n\xe0y trong trang t\xf9y ch\u1ecdn \u0111\u1ec3 b\u1ea3o m\u1eadt c\xe1c b\u1ea3n d\u1ecbch khi l\xe0m vi\u1ec7c v\u1edbi email, t\xe0i li\u1ec7u ho\u1eb7c tin nh\u1eafn c\xe1 nh\xe2n.\\n\\nTr\xecnh d\u1ecbch ngo\u1ea1i tuy\u1ebfn c\u0169ng cho ph\xe9p b\u1ea1n d\u1ecbch c\xe1c trang web m\xe0 kh\xf4ng c\u1ea7n k\u1ebft n\u1ed1i internet, \u0111\u1eb7c bi\u1ec7t h\u1eefu \xedch khi \u0111i du l\u1ecbch."},"fullPageTranslation":{"title":"D\u1ecbch to\xe0n b\u1ed9 trang web","content":"D\u1ecbch to\xe0n b\u1ed9 trang web nhanh ch\xf3ng, ch\u1ea5t l\u01b0\u1ee3ng cao ch\u1ec9 v\u1edbi v\xe0i c\xfa nh\u1ea5p chu\u1ed9t.\\n\\nS\u1eed d\u1ee5ng ph\xedm t\u1eaft \u0111\u1ec3 d\u1ecbch t\u1ee9c th\xec. Di chu\u1ed9t qua v\u0103n b\u1ea3n \u0111\xe3 d\u1ecbch \u0111\u1ec3 xem b\u1ea3n g\u1ed1c. D\u1ecbch c\u1ea3 nh\u1eefng trang ri\xeang t\u01b0 y\xeau c\u1ea7u \u0111\u0103ng nh\u1eadp ho\u1eb7c tr\u1ea3 ph\xed.\\n\\nThi\u1ebft l\u1eadp c\xe1c quy t\u1eafc d\u1ecbch t\u1ef1 \u0111\u1ed9ng d\u1ef1a tr\xean ng\xf4n ng\u1eef ho\u1eb7c t\xean mi\u1ec1n c\u1ee7a trang web.\\n\\nLinguist \xe1p d\u1ee5ng ph\u01b0\u01a1ng ph\xe1p can thi\u1ec7p t\u1ed1i thi\u1ec3u v\xe0o trang web: ti\u1ec7n \xedch ch\u1ec9 thay \u0111\u1ed5i c\xe1c ph\u1ea7n v\u0103n b\u1ea3n, \u0111\u1ed3ng th\u1eddi gi\u1eef nguy\xean b\u1ed1 c\u1ee5c trang v\xe0 tr\u1ea3i nghi\u1ec7m ng\u01b0\u1eddi d\xf9ng.\\n\\nB\u1eadt t\xednh n\u0103ng d\u1ecbch theo th\u1eddi gian th\u1ef1c cho c\xe1c cu\u1ed9c h\u1ecdp \u0111a ng\xf4n ng\u1eef tr\xean Zoom, Google Meet v\xe0 Microsoft Teams."},"selectedTextTranslation":{"title":"D\u1ecbch v\u0103n b\u1ea3n \u0111\u01b0\u1ee3c ch\u1ecdn","content":"B\u1eaft g\u1eb7p nh\u1eefng t\u1eeb l\u1ea1 khi \u0111ang \u0111\u1ecdc m\u1ed9t b\xe0i vi\u1ebft tr\u1ef1c tuy\u1ebfn?\\nB\u1ea1n ch\u1ec9 c\u1ea7n ch\u1ecdn \u0111o\u1ea1n v\u0103n b\u1ea3n tr\xean trang v\xe0 nh\u1ea5p v\xe0o n\xfat d\u1ecbch.\\n\\nNghe c\u1ea3 v\u0103n b\u1ea3n g\u1ed1c l\u1eabn b\u1ea3n d\u1ecbch, \u0111\u1ed3ng th\u1eddi l\u01b0u c\xe1c b\u1ea3n d\u1ecbch v\xe0o t\u1eeb \u0111i\u1ec3n c\u1ee7a b\u1ea1n \u0111\u1ec3 xem l\u1ea1i sau."},"textTranslation":{"title":"D\u1ecbch v\u0103n b\u1ea3n nhanh","content":"C\u1ea7n d\u1ecbch nhanh m\u1ed9t n\u1ed9i dung n\xe0o \u0111\xf3? H\xe3y nh\u1ea5p v\xe0o bi\u1ec3u t\u01b0\u1ee3ng Linguist v\xe0 nh\u1eadp v\u0103n b\u1ea3n c\u1ee7a b\u1ea1n.\\n\\nKh\xf4ng c\u1ea7n chuy\u1ec3n \u0111\u1ed5i gi\u1eefa c\xe1c tab hay m\u1edf c\xe1c trang web d\u1ecbch thu\u1eadt. D\u1ecbch tr\u1ef1c ti\u1ebfp ngay trong tr\xecnh duy\u1ec7t b\u1eb1ng d\u1ecbch v\u1ee5 m\xe0 b\u1ea1n y\xeau th\xedch."},"knowledgeBase":{"title":"X\xe2y d\u1ef1ng kho ki\u1ebfn th\u1ee9c c\xe1 nh\xe2n","content":"M\u1ecdi b\u1ea3n d\u1ecbch \u0111\u1ec1u \u0111\u01b0\u1ee3c l\u01b0u trong l\u1ecbch s\u1eed v\xe0 b\u1ea1n c\xf3 th\u1ec3 th\xeam c\xe1c m\u1ee5c quan tr\u1ecdng v\xe0o t\u1eeb \u0111i\u1ec3n c\xe1 nh\xe2n c\u1ee7a m\xecnh. T\xecm ki\u1ebfm trong t\u1eeb \u0111i\u1ec3n v\xe0 l\u1ecbch s\u1eed d\u1ecbch thu\u1eadt b\u1ea5t c\u1ee9 l\xfac n\xe0o.\\n\\nKh\xf4ng c\xf3 g\xec b\u1ecb m\u1ea5t \u0111i, ngay c\u1ea3 trong nh\u1eefng phi\xean nghi\xean c\u1ee9u ho\u1eb7c h\u1ecdc t\u1eadp k\xe9o d\xe0i.\\n\\nT\u1eeb \u0111i\u1ec3n ho\u1ea1t \u0111\u1ed9ng ngo\u1ea1i tuy\u1ebfn, bi\u1ebfn Linguist tr\u1edf th\xe0nh c\xf4ng c\u1ee5 l\xfd t\u01b0\u1edfng cho nh\u1eefng ng\u01b0\u1eddi h\u1ecdc ngo\u1ea1i ng\u1eef v\xe0 kh\xe1ch du l\u1ecbch c\u1ea7n truy c\u1eadp li\xean t\u1ee5c v\xe0o danh s\xe1ch t\u1eeb v\u1ef1ng c\u1ee7a h\u1ecd."},"customTranslators":{"title":"Tr\xecnh d\u1ecbch t\xf9y ch\u1ec9nh","content":"Linguist cho ph\xe9p b\u1ea1n ch\u1ecdn d\u1ecbch v\u1ee5 d\u1ecbch thu\u1eadt m\xe0 m\xecnh mu\u1ed1n s\u1eed d\u1ee5ng.\\n\\nTi\u1ec7n \xedch h\u1ed7 tr\u1ee3 c\xe1c nh\xe0 cung c\u1ea5p d\u1ecbch v\u1ee5 d\u1ecbch thu\u1eadt ph\u1ed5 bi\u1ebfn nh\u01b0 Google, Yandex v\xe0 Microsoft, v\u1edbi h\u01a1n 100 ng\xf4n ng\u1eef c\xf3 s\u1eb5n.\\n\\nN\u1ebfu d\u1ecbch v\u1ee5 b\u1ea1n c\u1ea7n kh\xf4ng c\xf3 s\u1eb5n, b\u1ea1n c\xf3 th\u1ec3 th\xeam d\u1ecbch v\u1ee5 \u0111\xf3 d\u01b0\u1edbi d\u1ea1ng <0>tr\xecnh d\u1ecbch t\xf9y ch\u1ec9nh</0>.\\n\\nTr\xecnh d\u1ecbch t\xf9y ch\u1ec9nh cho ph\xe9p b\u1ea1n t\xedch h\u1ee3p b\u1ea5t k\u1ef3 h\u1ec7 th\u1ed1ng d\u1ecbch thu\u1eadt n\xe0o \u2014 t\u1eeb c\xe1c d\u1ecbch v\u1ee5 LLM hi\u1ec7n \u0111\u1ea1i nh\u01b0 ChatGPT, DeepL, DeepSeek v\xe0 Gemini cho \u0111\u1ebfn c\xe1c tr\xecnh d\u1ecbch c\u1ee5c b\u1ed9 ch\u1ea1y tr\xean thi\u1ebft b\u1ecb c\u1ee7a b\u1ea1n, ch\u1eb3ng h\u1ea1n nh\u01b0 Ollama ho\u1eb7c LibreTranslate."}}},"faq":{"title":"C\xe2u h\u1ecfi th\u01b0\u1eddng g\u1eb7p","items":{"whatIsLinguist":{"title":"Linguist l\xe0 g\xec?","content":"Linguist l\xe0 m\u1ed9t ti\u1ec7n \xedch m\u1edf r\u1ed9ng d\u1ecbch thu\u1eadt \u01b0u ti\xean quy\u1ec1n ri\xeang t\u01b0 d\xe0nh cho Chrome v\xe0 Firefox.\\n\\nTi\u1ec7n \xedch n\xe0y cho ph\xe9p b\u1ea1n d\u1ecbch to\xe0n b\u1ed9 trang web, v\u0103n b\u1ea3n \u0111\u01b0\u1ee3c ch\u1ecdn, ph\u1ee5 \u0111\u1ec1 v\xe0 tin nh\u1eafn tr\u1ef1c ti\u1ebfp trong tr\xecnh duy\u1ec7t m\xe0 kh\xf4ng c\u1ea7n chuy\u1ec3n sang c\xe1c trang web d\u1ecbch thu\u1eadt b\xean ngo\xe0i."},"whyLinguist":{"title":"T\u1ea1i sao n\xean s\u1eed d\u1ee5ng Linguist?","content":"C\xf3 r\u1ea5t nhi\u1ec1u ti\u1ec7n \xedch m\u1edf r\u1ed9ng tr\xecnh duy\u1ec7t gi\xfap d\u1ecbch trang web v\xe0 m\u1ed9t s\u1ed1 tr\xecnh duy\u1ec7t th\u1eadm ch\xed c\xf2n t\xedch h\u1ee3p s\u1eb5n tr\xecnh d\u1ecbch. V\u1eady t\u1ea1i sao n\xean s\u1eed d\u1ee5ng Linguist?\\n\\nH\u1ea7u h\u1ebft c\xe1c tr\xecnh d\u1ecbch t\xedch h\u1ee3p v\xe0 ti\u1ec7n \xedch m\u1edf r\u1ed9ng d\u1ecbch thu\u1eadt \u0111\u1ec1u b\u1ecb h\u1ea1n ch\u1ebf v\u1ec1 t\xednh linh ho\u1ea1t. Nhi\u1ec1u c\xf4ng c\u1ee5 ch\u1ec9 d\u1ef1a v\xe0o m\u1ed9t nh\xe0 cung c\u1ea5p d\u1ecbch v\u1ee5 d\u1ecbch thu\u1eadt duy nh\u1ea5t nh\u01b0 Google D\u1ecbch ho\u1eb7c Microsoft Bing, trong khi Firefox cung c\u1ea5p tr\xecnh d\u1ecbch ngo\u1ea1i tuy\u1ebfn c\u1ee7a ri\xeang h\u1ecd. Trong h\u1ea7u h\u1ebft c\xe1c tr\u01b0\u1eddng h\u1ee3p, b\u1ea1n kh\xf4ng th\u1ec3 ch\u1ecdn d\u1ecbch v\u1ee5 ph\xf9 h\u1ee3p nh\u1ea5t v\u1edbi nhu c\u1ea7u c\u1ee7a m\xecnh.\\n\\nN\u1ebfu ch\u1ea5t l\u01b0\u1ee3ng b\u1ea3n d\u1ecbch kh\xf4ng \u0111\u1ee7 t\u1ed1t cho m\u1ee5c \u0111\xedch s\u1eed d\u1ee5ng c\u1ee7a b\u1ea1n, ho\u1eb7c n\u1ebfu vi\u1ec7c g\u1eedi v\u0103n b\u1ea3n ri\xeang t\u01b0 cho c\xe1c d\u1ecbch v\u1ee5 c\u1ee7a b\xean th\u1ee9 ba l\xe0 \u0111i\u1ec1u kh\xf4ng th\u1ec3 ch\u1ea5p nh\u1eadn \u0111\u01b0\u1ee3c, nhi\u1ec1u c\xf4ng c\u1ee5 s\u1ebd kh\xf4ng mang l\u1ea1i cho b\u1ea1n m\u1ed9t gi\u1ea3i ph\xe1p thay th\u1ebf t\u1ed1t n\xe0o.\\n\\nNhi\u1ec1u c\xf4ng c\u1ee5 c\u0169ng ch\u1ec9 t\u1eadp trung v\xe0o m\u1ed9t t\xe1c v\u1ee5 duy nh\u1ea5t. M\u1ed9t s\u1ed1 c\xf4ng c\u1ee5 d\u1ecbch to\xe0n b\u1ed9 trang web, trong khi nh\u1eefng c\xf4ng c\u1ee5 kh\xe1c ch\u1ec9 d\u1ecbch v\u0103n b\u1ea3n \u0111\u01b0\u1ee3c ch\u1ecdn.\\n\\n\u0110\u1ed3ng th\u1eddi, m\u1ed9t s\u1ed1 ti\u1ec7n \xedch m\u1edf r\u1ed9ng d\u1ecbch thu\u1eadt \u0111\u01b0\u1ee3c x\xe2y d\u1ef1ng ch\u1ee7 y\u1ebfu nh\u1eb1m m\u1ee5c \u0111\xedch ki\u1ebfm ti\u1ec1n. C\xe1c t\xednh n\u0103ng nh\u01b0 l\u1ecbch s\u1eed d\u1ecbch thu\u1eadt ho\u1eb7c t\u1eeb \u0111i\u1ec3n c\xe1 nh\xe2n c\xf3 th\u1ec3 y\xeau c\u1ea7u \u0111\u0103ng k\xfd tr\u1ea3 ph\xed v\xe0 \u0111\xf4i khi ngay c\u1ea3 nh\u1eefng t\xednh n\u0103ng c\u01a1 b\u1ea3n nh\u01b0 giao di\u1ec7n t\u1ed1i c\u0169ng b\u1ecb coi l\xe0 t\xf9y ch\u1ecdn cao c\u1ea5p.\\n\\nLinguist \xe1p d\u1ee5ng m\u1ed9t c\xe1ch ti\u1ebfp c\u1eadn kh\xe1c. Ti\u1ec7n \xedch n\xe0y \u0111\u01b0\u1ee3c thi\u1ebft k\u1ebf nh\u01b0 m\u1ed9t c\xf4ng c\u1ee5 d\u1ecbch thu\u1eadt thi\u1ebft th\u1ef1c. B\u1ea1n c\xf3 th\u1ec3 ch\u1ecdn d\u1ecbch v\u1ee5 d\u1ecbch thu\u1eadt ho\u1ea1t \u0111\u1ed9ng t\u1ed1t nh\u1ea5t cho m\xecnh, chuy\u1ec3n \u0111\u1ed5i gi\u1eefa c\xe1c nh\xe0 cung c\u1ea5p ho\u1eb7c th\xeam c\xe1c tr\xecnh d\u1ecbch t\xf9y ch\u1ec9nh c\u1ee7a ri\xeang b\u1ea1n.\\n\\nLinguist c\u0169ng t\u1eadp h\u1ee3p m\u1ecdi th\u1ee9 v\xe0o m\u1ed9t n\u01a1i: d\u1ecbch to\xe0n b\u1ed9 trang web, v\u0103n b\u1ea3n \u0111\u01b0\u1ee3c ch\u1ecdn, ph\u1ee5 \u0111\u1ec1 v\xe0 tin nh\u1eafn, \u0111\u1ed3ng th\u1eddi theo d\xf5i c\xe1c b\u1ea3n d\u1ecbch quan tr\u1ecdng trong l\u1ecbch s\u1eed v\xe0 t\u1eeb \u0111i\u1ec3n c\xe1 nh\xe2n c\u1ee7a b\u1ea1n."},"theLinguistLogo":{"title":"T\u1ea1i sao logo c\u1ee7a Linguist l\u1ea1i l\xe0 Th\xe1p Babel?","content":"Logo c\u1ee7a Linguist \u0111\u01b0\u1ee3c l\u1ea5y c\u1ea3m h\u1ee9ng t\u1eeb <wiki>Th\xe1p Babel</wiki>, m\u1ed9t trong nh\u1eefng c\xe2u chuy\u1ec7n l\xe2u \u0111\u1eddi nh\u1ea5t v\u1ec1 ng\xf4n ng\u1eef v\xe0 giao ti\u1ebfp.\\n\\nTheo c\xe2u chuy\u1ec7n, con ng\u01b0\u1eddi t\u1eebng n\xf3i c\xf9ng m\u1ed9t ng\xf4n ng\u1eef v\xe0 c\u1ed1 g\u1eafng x\xe2y d\u1ef1ng m\u1ed9t ng\u1ecdn th\xe1p ch\u1ea1m \u0111\u1ebfn b\u1ea7u tr\u1eddi. Ng\u1ecdn th\xe1p kh\xf4ng bao gi\u1edd \u0111\u01b0\u1ee3c ho\xe0n th\xe0nh v\xe0 nh\xe2n lo\u1ea1i b\u1ecb ph\xe2n t\xe1n qua nhi\u1ec1u ng\xf4n ng\u1eef kh\xe1c nhau. K\u1ec3 t\u1eeb \u0111\xf3, s\u1ef1 kh\xe1c bi\u1ec7t v\u1ec1 ng\xf4n ng\u1eef th\u01b0\u1eddng khi\u1ebfn vi\u1ec7c giao ti\u1ebfp tr\u1edf n\xean kh\xf3 kh\u0103n h\u01a1n.\\n\\nLinguist \u0111\u01b0\u1ee3c t\u1ea1o ra \u0111\u1ec3 gi\xfap gi\u1ea3i quy\u1ebft v\u1ea5n \u0111\u1ec1 n\xe0y.\\n\\nTh\xe1p Babel trong logo l\xe0 m\u1ed9t l\u1eddi nh\u1eafc nh\u1edf v\u1ec1 c\xe2u chuy\u1ec7n \u0111\xf3: nhi\u1ec1u ng\xf4n ng\u1eef, nhi\u1ec1u n\u1ec1n v\u0103n h\xf3a v\xe0 n\u1ed7 l\u1ef1c kh\xf4ng ng\u1eebng c\u1ee7a con ng\u01b0\u1eddi \u0111\u1ec3 th\u1ea5u hi\u1ec3u l\u1eabn nhau. Linguist gi\xfap thu h\u1eb9p nh\u1eefng kho\u1ea3ng c\xe1ch \u0111\xf3 b\u1eb1ng c\xe1ch l\xe0m cho vi\u1ec7c d\u1ecbch thu\u1eadt tr\u1edf n\xean \u0111\u01a1n gi\u1ea3n, linh ho\u1ea1t v\xe0 d\u1ec5 ti\u1ebfp c\u1eadn ngay trong tr\xecnh duy\u1ec7t c\u1ee7a b\u1ea1n.\\n\\nLogo c\u0169ng ph\u1ea3n \xe1nh tinh th\u1ea7n c\u1ee7a d\u1ef1 \xe1n. Linguist kh\xf4ng ch\u1ec9 l\xe0 m\u1ed9t l\u1edbp v\u1ecf b\u1ecdc kh\xe1c c\u1ee7a \\"Google D\u1ecbch\\". Ti\u1ec7n \xedch n\xe0y \u0111\u01b0\u1ee3c x\xe2y d\u1ef1ng b\u1edfi nh\u1eefng ng\u01b0\u1eddi quan t\xe2m \u0111\u1ebfn ng\xf4n ng\u1eef, quy\u1ec1n ri\xeang t\u01b0 v\xe0 c\xf4ng ngh\u1ec7 m\u1edf. Th\xe1p Babel t\u01b0\u1ee3ng tr\u01b0ng cho s\u1ef1 t\xf2 m\xf2, tinh th\u1ea7n h\u1ecdc h\u1ecfi v\xe0 \xfd t\u01b0\u1edfng r\u1eb1ng s\u1ef1 kh\xe1c bi\u1ec7t v\u1ec1 ng\xf4n ng\u1eef n\xean mang m\u1ecdi ng\u01b0\u1eddi \u0111\u1ebfn g\u1ea7n nhau h\u01a1n thay v\xec chia c\u1eaft h\u1ecd."},"imageTranslation":{"title":"T\u1ea1i sao Linguist kh\xf4ng d\u1ecbch v\u0103n b\u1ea3n trong h\xecnh \u1ea3nh?","content":"Linguist t\u1eadp trung v\xe0o c\xe1c t\xednh n\u0103ng d\u1ecbch thu\u1eadt \u0111\xe1ng tin c\u1eady v\xe0 ch\u1ea5t l\u01b0\u1ee3ng cao.\\n\\nCh\xfang t\xf4i \u0111\xe3 nghi\xean c\u1ee9u nhi\u1ec1u ph\u01b0\u01a1ng ph\xe1p kh\xe1c nhau \u0111\u1ec3 d\u1ecbch v\u0103n b\u1ea3n b\xean trong h\xecnh \u1ea3nh. Hi\u1ec7n t\u1ea1i, h\u1ea7u h\u1ebft c\xe1c gi\u1ea3i ph\xe1p c\xf3 s\u1eb5n \u0111\u1ec1u kh\xf4ng mang l\u1ea1i k\u1ebft qu\u1ea3 nh\u1ea5t qu\xe1n, \u0111\u1eb7c bi\u1ec7t l\xe0 khi ch\u1ea1y tr\u1ef1c ti\u1ebfp trong tr\xecnh duy\u1ec7t \u2014 \u0111i\u1ec1u v\u1ed1n r\u1ea5t quan tr\u1ecdng \u0111\u1ec3 duy tr\xec quy\u1ec1n ri\xeang t\u01b0 c\u1ee7a ng\u01b0\u1eddi d\xf9ng.\\n\\nV\xec l\xfd do n\xe0y, Linguist hi\u1ec7n kh\xf4ng bao g\u1ed3m t\xednh n\u0103ng d\u1ecbch h\xecnh \u1ea3nh. Ch\xfang t\xf4i kh\xf4ng mu\u1ed1n ph\xe1t h\xe0nh nh\u1eefng t\xednh n\u0103ng kh\xf4ng \u0111\xe1p \u1ee9ng \u0111\u01b0\u1ee3c ti\xeau chu\u1ea9n ch\u1ea5t l\u01b0\u1ee3ng c\u1ee7a m\xecnh.\\n\\nN\u1ebfu trong t\u01b0\u01a1ng lai ch\xfang t\xf4i t\xecm ra m\u1ed9t c\xe1ch \u0111\xe1ng tin c\u1eady v\xe0 t\xf4n tr\u1ecdng quy\u1ec1n ri\xeang t\u01b0 \u0111\u1ec3 tri\u1ec3n khai t\xednh n\u0103ng d\u1ecbch h\xecnh \u1ea3nh, ch\xfang t\xf4i s\u1ebd r\u1ea5t s\u1eb5n l\xf2ng b\u1ed5 sung t\xednh n\u0103ng n\xe0y."},"howTranslatePages":{"title":"Linguist d\u1ecbch c\xe1c trang web nh\u01b0 th\u1ebf n\xe0o?","content":"Linguist c\xf3 th\u1ec3 d\u1ecbch to\xe0n b\u1ed9 trang web ch\u1ec9 v\u1edbi v\xe0i c\xfa nh\u1ea5p chu\u1ed9t. B\u1ea1n c\xf3 th\u1ec3 b\u1eaft \u0111\u1ea7u d\u1ecbch trang b\u1eb1ng c\xe1ch s\u1eed d\u1ee5ng n\xfat c\u1ee7a ti\u1ec7n \xedch m\u1edf r\u1ed9ng ho\u1eb7c ph\xedm t\u1eaft.\\n\\nV\u0103n b\u1ea3n g\u1ed1c lu\xf4n c\xf3 th\u1ec3 truy c\u1eadp \u0111\u01b0\u1ee3c. H\xe3y di chu\u1ed9t qua v\u0103n b\u1ea3n \u0111\xe3 d\u1ecbch \u0111\u1ec3 xem b\u1ea3n g\u1ed1c."},"offlineTranslation":{"title":"Linguist c\xf3 th\u1ec3 d\u1ecbch trang web ngo\u1ea1i tuy\u1ebfn kh\xf4ng?","content":"C\xf3. Linguist bao g\u1ed3m m\u1ed9t tr\xecnh d\u1ecbch ngo\u1ea1i tuy\u1ebfn \u0111\u01b0\u1ee3c t\xedch h\u1ee3p s\u1eb5n, cho ph\xe9p b\u1ea1n d\u1ecbch v\u0103n b\u1ea3n m\xe0 kh\xf4ng c\u1ea7n g\u1eedi d\u1eef li\u1ec7u qua internet.\\n\\n\u0110i\u1ec1u n\xe0y gi\xfap b\u1ea3o v\u1ec7 quy\u1ec1n ri\xeang t\u01b0 c\u1ee7a b\u1ea1n v\xe0 cho ph\xe9p b\u1ea1n d\u1ecbch n\u1ed9i dung ngay c\u1ea3 khi kh\xf4ng c\xf3 k\u1ebft n\u1ed1i internet."},"privacy":{"title":"Linguist c\xf3 b\u1ea3o m\u1eadt quy\u1ec1n ri\xeang t\u01b0 kh\xf4ng?","content":"C\xf3. Linguist \u0111\u01b0\u1ee3c thi\u1ebft k\u1ebf v\u1edbi \u01b0u ti\xean h\xe0ng \u0111\u1ea7u l\xe0 quy\u1ec1n ri\xeang t\u01b0.\\n\\nTi\u1ec7n \xedch m\u1edf r\u1ed9ng n\xe0y kh\xf4ng thu th\u1eadp hay b\xe1n d\u1eef li\u1ec7u ng\u01b0\u1eddi d\xf9ng. Khi s\u1eed d\u1ee5ng <offline-translator>tr\xecnh d\u1ecbch ngo\u1ea1i tuy\u1ebfn</offline-translator>, c\xe1c b\u1ea3n d\u1ecbch \u0111\u01b0\u1ee3c x\u1eed l\xfd ho\xe0n to\xe0n tr\xean thi\u1ebft b\u1ecb c\u1ee7a b\u1ea1n."},"supportedBrowsers":{"title":"Linguist h\u1ed7 tr\u1ee3 nh\u1eefng tr\xecnh duy\u1ec7t n\xe0o?","content":"Linguist hi\u1ec7n c\xf3 s\u1eb5n cho Chrome v\xe0 Firefox. Ti\u1ec7n \xedch n\xe0y c\u0169ng ho\u1ea1t \u0111\u1ed9ng tr\xean c\xe1c tr\xecnh duy\u1ec7t d\u1ef1a tr\xean Chromium kh\xe1c c\xf3 h\u1ed7 tr\u1ee3 ti\u1ec7n \xedch m\u1edf r\u1ed9ng c\u1ee7a Chrome.\\n\\nLinguist c\u0169ng ho\u1ea1t \u0111\u1ed9ng tr\xean c\xe1c tr\xecnh duy\u1ec7t Android c\xf3 h\u1ed7 tr\u1ee3 ti\u1ec7n \xedch m\u1edf r\u1ed9ng, ch\u1eb3ng h\u1ea1n nh\u01b0 Firefox cho Android v\xe0 m\u1ed9t s\u1ed1 tr\xecnh duy\u1ec7t d\u1ef1a tr\xean Chromium."},"selectedText":{"title":"Linguist c\xf3 th\u1ec3 d\u1ecbch v\u0103n b\u1ea3n \u0111\u01b0\u1ee3c ch\u1ecdn kh\xf4ng?","content":"C\xf3. B\u1ea1n ch\u1ec9 c\u1ea7n ch\u1ecdn v\u0103n b\u1ea3n tr\xean b\u1ea5t k\u1ef3 trang web n\xe0o v\xe0 s\u1eed d\u1ee5ng n\xfat d\u1ecbch \u0111\u1ec3 d\u1ecbch t\u1ee9c th\xec.\\n\\nB\u1ea1n c\u0169ng c\xf3 th\u1ec3 nghe b\u1ea3n d\u1ecbch v\xe0 l\u01b0u v\xe0o t\u1eeb \u0111i\u1ec3n c\xe1 nh\xe2n c\u1ee7a m\xecnh."},"customTranslators":{"title":"T\xf4i c\xf3 th\u1ec3 s\u1eed d\u1ee5ng d\u1ecbch v\u1ee5 d\u1ecbch thu\u1eadt c\u1ee7a ri\xeang m\xecnh kh\xf4ng?","content":"C\xf3. Linguist h\u1ed7 tr\u1ee3 c\xe1c <custom-translator>tr\xecnh d\u1ecbch t\xf9y ch\u1ec9nh</custom-translator>, cho ph\xe9p b\u1ea1n t\xedch h\u1ee3p th\xeam c\xe1c d\u1ecbch v\u1ee5 d\u1ecbch thu\u1eadt kh\xe1c.\\n\\nB\u1ea1n c\xf3 th\u1ec3 k\u1ebft n\u1ed1i c\xe1c API b\xean ngo\xe0i ho\u1eb7c c\xe1c h\u1ec7 th\u1ed1ng d\u1ecbch thu\u1eadt c\u1ee5c b\u1ed9 nh\u01b0 <libre-translate>LibreTranslate</libre-translate> ho\u1eb7c <ollama>Ollama</ollama>."},"isFree":{"title":"Linguist c\xf3 mi\u1ec5n ph\xed kh\xf4ng?","content":"C\xf3. Linguist ho\xe0n to\xe0n mi\u1ec5n ph\xed v\xe0 l\xe0 <linguist>m\xe3 ngu\u1ed3n m\u1edf</linguist>.\\n\\nD\u1ef1 \xe1n \u0111\u01b0\u1ee3c h\u1ed7 tr\u1ee3 b\u1edfi c\u1ed9ng \u0111\u1ed3ng v\xe0 b\u1ea1n c\xf3 th\u1ec3 t\xf9y ch\u1ecdn <donations>\u1ee7ng h\u1ed9 d\u1ef1 \xe1n b\u1eb1ng c\xe1ch quy\xean g\xf3p</donations>."}}}}},"altVersions":[{"langCode":"ar","langName":"\u0627\u0644\u0639\u0631\u0628\u064a\u0629","url":"https://linguister.io/ar"},{"langCode":"bn","langName":"\u09ac\u09be\u0982\u09b2\u09be","url":"https://linguister.io/bn"},{"langCode":"de","langName":"Deutsch","url":"https://linguister.io/de"},{"langCode":"en","langName":"English","url":"https://linguister.io/"},{"langCode":"es","langName":"espa\xf1ol","url":"https://linguister.io/es"},{"langCode":"fr","langName":"fran\xe7ais","url":"https://linguister.io/fr"},{"langCode":"gu","langName":"\u0a97\u0ac1\u0a9c\u0ab0\u0abe\u0aa4\u0ac0","url":"https://linguister.io/gu"},{"langCode":"hi","langName":"\u0939\u093f\u0928\u094d\u0926\u0940","url":"https://linguister.io/hi"},{"langCode":"it","langName":"italiano","url":"https://linguister.io/it"},{"langCode":"ja","langName":"\u65e5\u672c\u8a9e","url":"https://linguister.io/ja"},{"langCode":"jv","langName":"Jawa","url":"https://linguister.io/jv"},{"langCode":"ko","langName":"\ud55c\uad6d\uc5b4","url":"https://linguister.io/ko"},{"langCode":"mr","langName":"\u092e\u0930\u093e\u0920\u0940","url":"https://linguister.io/mr"},{"langCode":"pa","langName":"\u0a2a\u0a70\u0a1c\u0a3e\u0a2c\u0a40","url":"https://linguister.io/pa"},{"langCode":"pt","langName":"portugu\xeas","url":"https://linguister.io/pt"},{"langCode":"ru","langName":"\u0440\u0443\u0441\u0441\u043a\u0438\u0439","url":"https://linguister.io/ru"},{"langCode":"ta","langName":"\u0ba4\u0bae\u0bbf\u0bb4\u0bcd","url":"https://linguister.io/ta"},{"langCode":"tr","langName":"T\xfcrk\xe7e","url":"https://linguister.io/tr"},{"langCode":"ur","langName":"\u0627\u0631\u062f\u0648","url":"https://linguister.io/ur"},{"langCode":"vi","langName":"Ti\u1ebfng Vi\u1ec7t","url":"https://linguister.io/vi"},{"langCode":"zh","langName":"\u4e2d\u6587","url":"https://linguister.io/zh"}]}')}}]);